(function () {
  var CDN_URLS = [
    'https://cdn.jsdelivr.net/npm/epubjs/dist/epub.min.js',
    'https://unpkg.com/epubjs/dist/epub.min.js',
    'https://cdnjs.cloudflare.com/ajax/libs/epub.js/latest/epub.min.js'
  ];
  var index = 0;

  function loadScript(url, onSuccess, onError) {
    var script = document.createElement('script');
    script.type = 'text/javascript';
    script.src = url;
    script.async = false;
    script.onload = onSuccess;
    script.onerror = onError;
    document.head.appendChild(script);
  }

  function tryNext() {
    if (index >= CDN_URLS.length) {
      console.error('[epub.min.js] Failed to load epub.js from all CDN sources.');
      return;
    }
    var url = CDN_URLS[index++];
    loadScript(
      url,
      function () {
        console.log('[epub.min.js] Loaded epub.js from ' + url);
      },
      function () {
        console.warn('[epub.min.js] Failed to load from ' + url + ', trying next...');
        tryNext();
      }
    );
  }

  tryNext();
})();
